using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to retrieve (e.g. 'MaxRetries', 'Timeout')")] string key)
    {
        var config = AppConfig.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Updates a configuration value. Returns the previous and new values.")]
    public static string SetConfigValue(
        [Description("The configuration key to update")] string key,
        [Description("The new value to assign")] string value)
    {
        var config = AppConfig.Current;
        var previous = config.TryGetValue(key, out var old) ? old : "(not set)";
        config[key] = value;
        return $"{key}: {previous} → {value}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/all", Name = "Full App Config",
        MimeType = "application/json"),
     Description("Returns the complete application configuration as JSON.")]
    public static string GetAllConfig() =>
        JsonSerializer.Serialize(AppConfig.Current, AppConfig.SerializerOptions);
}

using System.Text.Json;

public static class AppConfig
{
    public static Dictionary<string, string> Current { get; } = new()
    {
        ["MaxRetries"] = "3",
        ["Timeout"] = "30s",
        ["LogLevel"] = "Information",
        ["Region"] = "us-east-1"
    };

    public static JsonSerializerOptions SerializerOptions { get; } = new()
    {
        WriteIndented = true
    };
}

